function buildBreedHref(query?: string, group?: string) {
  const params = new URLSearchParams()
  if (query) params.set("q", query)
  if (group) params.set("grupo", group)
  const search = params.toString()
  return search ? `/racas?${search}` : "/racas"
}

function resolveBreedQuery(query: string) {
  const normalized = normalizeQuery(query)
  return BREED_QUERY_ALIASES.get(normalized) || query
}

function normalizeQuery(value: string) {
  return value
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim()
}

function poundsToKg(value: number) {
  return Number((value * 0.453592).toFixed(1))
}

function inchesToCm(value: number) {
  return Math.round(value * 2.54)
}

function inferBreedPurpose(group: string) {
  const normalized = mapApiGroupToValue(group || "")

  if (normalized === "herding") return "herding livestock"
  if (normalized === "working") return "guarding and service work"
  if (normalized === "sporting") return "retrieving and field work"
  if (normalized === "hound") return "hunting and scent work"
  if (normalized === "terrier") return "small game hunting"
  if (normalized === "toy") return "companion work"
  if (normalized === "non-sporting") return "companion and utility work"
  return "companion work"
}

function adaptBreedToStudyProfile(breed: Breed): BreedStudyProfile {
  const temperament = breed.general.personalityTraits.join(", ")
  const base = buildBreedStudyProfile({
    id: breed.id,
    name: breed.general.name,
    breedGroup: breed.general.group || "Mixed",
    origin: null,
    temperament,
    description: breed.general.longDescription || breed.general.shortDescription || null,
    lifeSpan: `${breed.general.lifespan} years`,
    bredFor: inferBreedPurpose(breed.general.group),
    perfectFor: inferBreedPurpose(breed.general.group),
    history: breed.general.longDescription || null,
    countryCode: null,
    weightMinKg: poundsToKg(breed.general.weight),
    weightMaxKg: poundsToKg(breed.general.weight),
    heightReferenceCm: `${inchesToCm(breed.general.height)} cm`,
    heightMinCm: inchesToCm(breed.general.height),
    heightMaxCm: inchesToCm(breed.general.height),
    referenceImageUrl: breed.images.studio || breed.images.outdoors || breed.images.indoors || null,
  })

  return {
    ...base,
    studyHighlights: buildRegistryStudyHighlights(breed, base),
  }
}

function buildRegistryStudyHighlights(breed: Breed, profile: BreedStudyProfile): BreedStudyHighlight[] {
  const familyScore = average([
    breed.behavior.familyAffection,
    breed.behavior.childFriendly,
    breed.behavior.dogSociability,
  ])
  const careScore = average([
    breed.care.sheddingAmount,
    breed.care.groomingFrequency,
    breed.physical.droolingFrequency,
  ])
  const athleteScore = average([
    breed.care.exerciseNeeds,
    breed.care.mentalStimulationNeeds,
    breed.behavior.playfulness,
  ])
  const urbanScore = average([
    breed.behavior.adaptability,
    6 - breed.behavior.barkingFrequency,
    profile.energy.score <= 3 ? 4 : 2,
  ])

  return [
    {
      title: "Vida em familia",
      description: describeFamilyLife(familyScore),
    },
    {
      title: "Cuidado no dia a dia",
      description: describeCareLoad(careScore, breed),
    },
    {
      title: "Potencial esportivo",
      description: describeAthletePotential(athleteScore, profile),
    },
    {
      title: "Casa e rotina",
      description: describeHomeFit(urbanScore, profile),
    },
  ]
}

function describeFamilyLife(score: number) {
  if (score >= 4.2) {
    return "Costuma combinar bem com casas presentes, convivio frequente e rotina de familia, desde que a educacao comece cedo."
  }
  if (score >= 3.2) {
    return "Tende a conviver bem em familia, mas o resultado depende de socializacao, limites claros e rotina coerente."
  }
  return "Pede apresentacao mais cuidadosa, leitura do ambiente e socializacao caprichada para construir convivio equilibrado."
}

function describeCareLoad(score: number, breed: Breed) {
  const coat =
    breed.physical.coatTexture && breed.physical.coatStyle
      ? `Pelagem ${breed.physical.coatTexture.toLowerCase()} com base ${breed.physical.coatStyle.toLowerCase()}.`
      : "A pelagem precisa entrar na decisao."

  if (score >= 4.2) {
    return `${coat} A manutencao tende a ser alta, com mais escovacao, limpeza e atencao recorrente no manejo.`
  }
  if (score >= 3.2) {
    return `${coat} A manutencao fica em faixa moderada e costuma pedir constancia semanal do tutor.`
  }
  return `${coat} A rotina de cuidado tende a ser mais simples, mas ainda exige observacao, banho e manejo regulares.`
}

function describeAthletePotential(score: number, profile: BreedStudyProfile) {
  if (score >= 4.2 || profile.energy.score >= 4) {
    return "Tem base forte para esporte, rotina ativa, desafios mentais e projetos de treino com mais intensidade."
  }
  if (score >= 3.2) {
    return "Pode evoluir bem em atividades regulares, trilhas, obediencia funcional e rotinas com boa variedade."
  }
  return "Costuma funcionar melhor com atividade equilibrada e constancia, sem depender de uma carga fisica muito intensa."
}

function describeHomeFit(score: number, profile: BreedStudyProfile) {
  if (score >= 4.2) {
    return `Tende a se adaptar melhor ao cotidiano da casa quando o tutor mantem previsibilidade, passeio e rotina proporcional ao perfil ${profile.groupLabel.toLowerCase()}.`
  }
  if (score >= 3.2) {
    return "Pode viver bem em diferentes contextos, desde que o tutor respeite energia, barulho, manejo e necessidades de treino."
  }
  return "Nao e um perfil para ficar no automatico. O ambiente precisa ser pensado junto com espaco, enriquecimento e disciplina."
}

function average(values: number[]) {
  const valid = values.filter((value) => Number.isFinite(value))
  if (valid.length === 0) return 3
  return valid.reduce((total, value) => total + value, 0) / valid.length
}

